




















import Vue from 'vue'

import AnimatedTitle from '@/components/ui/AnimatedTitle.vue'

export default Vue.extend({
	components: {
		AnimatedTitle,
	},
	data() {
		return {
			active: false,
		}
	},
	props: {
		timeEvents: {
			type: Array as () => TimeEvent[],
			required: true
		},
		title: {
			type: String,
			required: false
		},
		icon: {
			type: String,
			required: false
		}
	}
})
